messages.content:
{
  "children": [
    {
      "name": "ValidateCommand",
      "purpose": "Validate that the command is one of the four allowed values and that required fields in message_data are present based on command type.",
      "behavior": "Check command against allowed set; for each command, verify required keys in message_data (e.g., channel_id for send/history/join, channel_name for create_channel, content for send). Return error if invalid.",
      "boundary": {
        "in_scope": [
          "command validation",
          "required field presence check"
        ],
        "out_of_scope": [
          "business logic",
          "data access"
        ]
      },
      "preconditions": [
        "command and message_data are provided"
      ],
      "postconditions": [
        "Validation result is produced"
      ],
      "guarantees": [
        "Only valid commands and required fields proceed"
      ],
      "composition_role": "validate",
      "stop_decompose": true,
      "stop_reason": "Pure validation logic, no further decomposition needed",
      "inputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Chat command string",
          "source": "parent input"
        },
        {
          "name": "message_data",
          "type": "dict",
          "description": "Message payload dictionary",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "validation_result",
          "type": "dict",
          "description": "Dictionary with success (bool), data (None), message (str) indicating valid or error",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateCommand(command: str, message_data: dict) -> dict"
    },
    {
      "name": "SendMessage",
      "purpose": "Handle the 'send' command: verify user membership, store message, update user's last_seen, notify other channel members.",
      "behavior": "Check if user_id is in channel's members list; if not, return error. Generate new message_id, store message in messages store with timestamp. Update user's last_seen in users store. Notify other channel members (simulated as adding to a notification list or logging). Return success with message data.",
      "boundary": {
        "in_scope": [
          "membership check",
          "message storage",
          "last_seen update",
          "notification"
        ],
        "out_of_scope": [
          "other commands",
          "history retrieval"
        ]
      },
      "preconditions": [
        "command is 'send'",
        "validation passed"
      ],
      "postconditions": [
        "Message stored if user is member",
        "User's last_seen updated",
        "Notification sent"
      ],
      "guarantees": [
        "Only members can send",
        "Message is stored with timestamp"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "Can be further decomposed into membership check, store, update, notify",
      "inputs": [
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains content, channel_id, user_id",
          "source": "parent input"
        },
        {
          "name": "channels",
          "type": "dict",
          "description": "Channel data store for membership check",
          "source": "global variable"
        },
        {
          "name": "messages",
          "type": "dict",
          "description": "Message store for writing",
          "source": "global variable"
        },
        {
          "name": "users",
          "type": "dict",
          "description": "User store for updating last_seen",
          "source": "global variable"
        }
      ],
      "outputs": [
        {
          "name": "send_result",
          "type": "dict",
          "description": "Dictionary with success (bool), data (dict with message_id, content, timestamp, channel_id, user_id), message (str)",
          "consumer": "parent"
        }
      ],
      "signature": "def SendMessage(message_data: dict, channels: dict, messages: dict, users: dict) -> dict"
    },
    {
      "name": "GetHistory",
      "purpose": "Handle the 'history' command: retrieve last 100 messages from a channel sorted by timestamp descending.",
      "behavior": "Query messages store for all messages with given channel_id, sort by timestamp descending, limit to 100, return as list.",
      "boundary": {
        "in_scope": [
          "message retrieval",
          "sorting",
          "limiting"
        ],
        "out_of_scope": [
          "other commands",
          "membership check"
        ]
      },
      "preconditions": [
        "command is 'history'",
        "validation passed"
      ],
      "postconditions": [
        "Messages retrieved and sorted"
      ],
      "guarantees": [
        "Returns at most 100 messages",
        "Sorted by timestamp descending"
      ],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "Atomic read operation with sorting and limit",
      "inputs": [
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains channel_id",
          "source": "parent input"
        },
        {
          "name": "messages",
          "type": "dict",
          "description": "Message store for reading",
          "source": "global variable"
        }
      ],
      "outputs": [
        {
          "name": "history_result",
          "type": "dict",
          "description": "Dictionary with success (bool), data (list of message dicts), message (str)",
          "consumer": "parent"
        }
      ],
      "signature": "def GetHistory(message_data: dict, messages: dict) -> dict"
    },
    {
      "name": "CreateChannel",
      "purpose": "Handle the 'create_channel' command: create new channel with unique name, set caller as creator and first member.",
      "behavior": "Check if channel_name already exists in channels store; if so, return error. Generate new channel_id, store channel with name, members list containing user_id, created_by set to user_id. Return success with channel data.",
      "boundary": {
        "in_scope": [
          "uniqueness check",
          "channel creation",
          "membership initialization"
        ],
        "out_of_scope": [
          "other commands",
          "message storage"
        ]
      },
      "preconditions": [
        "command is 'create_channel'",
        "validation passed"
      ],
      "postconditions": [
        "New channel created if name unique",
        "User is first member and creator"
      ],
      "guarantees": [
        "Channel name is unique"
      ],
      "composition_role": "execute",
      "stop_decompose": true,
      "stop_reason": "Single atomic operation with uniqueness check",
      "inputs": [
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains channel_name, user_id",
          "source": "parent input"
        },
        {
          "name": "channels",
          "type": "dict",
          "description": "Channel data store for reading and writing",
          "source": "global variable"
        }
      ],
      "outputs": [
        {
          "name": "create_result",
          "type": "dict",
          "description": "Dictionary with success (bool), data (dict with channel_id, channel_name, members, created_by), message (str)",
          "consumer": "parent"
        }
      ],
      "signature": "def CreateChannel(message_data: dict, channels: dict) -> dict"
    },
    {
      "name": "JoinChannel",
      "purpose": "Handle the 'join' command: add user to channel's member list if not already a member.",
      "behavior": "Check if user_id is already in channel's members list; if so, return error. Otherwise, add user_id to members list in channels store. Return success with updated member list.",
      "boundary": {
        "in_scope": [
          "membership check",
          "member addition"
        ],
        "out_of_scope": [
          "other commands",
          "message storage"
        ]
      },
      "preconditions": [
        "command is 'join'",
        "validation passed"
      ],
      "postconditions": [
        "User added to channel members if not already member"
      ],
      "guarantees": [
        "No duplicate membership"
      ],
      "composition_role": "mutate",
      "stop_decompose": true,
      "stop_reason": "Single atomic operation with membership check",
      "inputs": [
        {
          "name": "message_data",
          "type": "dict",
          "description": "Contains channel_id, user_id",
          "source": "parent input"
        },
        {
          "name": "channels",
          "type": "dict",
          "description": "Channel data store for reading and writing",
          "source": "global variable"
        }
      ],
      "outputs": [
        {
          "name": "join_result",
          "type": "dict",
          "description": "Dictionary with success (bool), data (dict with channel_id, members list), message (str)",
          "consumer": "parent"
        }
      ],
      "signature": "def JoinChannel(message_data: dict, channels: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "command": [
        "ValidateCommand"
      ],
      "message_data": [
        "ValidateCommand",
        "SendMessage",
        "GetHistory",
        "CreateChannel",
        "JoinChannel"
      ]
    },
    "parent_outputs_produced_by": {
      "message_result": [
        "ValidateCommand",
        "SendMessage",
        "GetHistory",
        "CreateChannel",
        "JoinChannel"
      ]
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "command",
      "to_node": "ValidateCommand",
      "to_input": "command",
      "note": "Pass command for validation"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "ValidateCommand",
      "to_input": "message_data",
      "note": "Pass message_data for validation"
    },
    {
      "from_node": "ValidateCommand",
      "from_output": "validation_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "Return validation result to parent"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "SendMessage",
      "to_input": "message_data",
      "note": "Pass message_data to send handler"
    },
    {
      "from_node": "global",
      "from_output": "channels",
      "to_node": "SendMessage",
      "to_input": "channels",
      "note": "Provide channels store for membership check"
    },
    {
      "from_node": "global",
      "from_output": "messages",
      "to_node": "SendMessage",
      "to_input": "messages",
      "note": "Provide messages store for writing"
    },
    {
      "from_node": "global",
      "from_output": "users",
      "to_node": "SendMessage",
      "to_input": "users",
      "note": "Provide users store for last_seen update"
    },
    {
      "from_node": "SendMessage",
      "from_output": "send_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "Return send result to parent"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "GetHistory",
      "to_input": "message_data",
      "note": "Pass message_data to history handler"
    },
    {
      "from_node": "global",
      "from_output": "messages",
      "to_node": "GetHistory",
      "to_input": "messages",
      "note": "Provide messages store for reading"
    },
    {
      "from_node": "GetHistory",
      "from_output": "history_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "Return history result to parent"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "CreateChannel",
      "to_input": "message_data",
      "note": "Pass message_data to create channel handler"
    },
    {
      "from_node": "global",
      "from_output": "channels",
      "to_node": "CreateChannel",
      "to_input": "channels",
      "note": "Provide channels store for reading and writing"
    },
    {
      "from_node": "CreateChannel",
      "from_output": "create_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "Return create result to parent"
    },
    {
      "from_node": "parent",
      "from_output": "message_data",
      "to_node": "JoinChannel",
      "to_input": "message_data",
      "note": "Pass message_data to join handler"
    },
    {
      "from_node": "global",
      "from_output": "channels",
      "to_node": "JoinChannel",
      "to_input": "channels",
      "note": "Provide channels store for reading and writing"
    },
    {
      "from_node": "JoinChannel",
      "from_output": "join_result",
      "to_node": "parent",
      "to_input": "message_result",
      "note": "Return join result to parent"
    }
  ]
}
